mapper.select:
SELECT t.id AS task_id, t.task_name, t.task_type, t.status, t.project_id, p.project_name, p.project_code, t.execute_mode, t.priority, t.planned_start, t.planned_end, CASE WHEN t.planned_end IS NOT NULL AND t.planned_end < CURDATE() AND t.status NOT IN ('COMPLETED', 'CONFIRMED') THEN 1 ELSE 0 END AS overdue FROM project_task t INNER JOIN project p ON p.id = t.project_id AND p.deleted = 0 INNER JOIN engineer e ON e.id = t.assignee_id AND e.deleted = 0 WHERE t.deleted = 0 AND e.user_id = #{userId}
AND t.status = #{status}
ORDER BY overdue DESC, t.planned_end ASC
LIMIT #{limit}

SELECT COUNT(*) FROM project_task t
INNER JOIN engineer e ON e.id = t.assignee_id AND e.deleted = 0
WHERE t.deleted = 0 AND e.user_id = #{userId}
  AND t.planned_end IS NOT NULL
  AND t.planned_end < #{today}
  AND t.status NOT IN ('COMPLETED', 'CONFIRMED')

SELECT COALESCE(SUM(ts.hours), 0)
FROM timesheet ts
INNER JOIN engineer e ON e.id = ts.engineer_id AND e.deleted = 0
WHERE ts.deleted = 0
  AND e.user_id = #{userId}
  AND ts.work_date >= #{startDay}
  AND ts.work_date <= #{endDay}
